import React, { useState } from "react";
import { getPasswordStrength } from "../utils/validators";

const base = {
  field: { marginBottom: "16px" },
  label: { display: "block", fontSize: "12px", fontWeight: 600, color: "#444", marginBottom: "5px", letterSpacing: ".3px" },
  wrap: { position: "relative" },
  input: {
    width: "100%", padding: "10px 40px 10px 12px",
    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
    fontSize: "14px", background: "var(--input-bg)", color: "var(--text-primary)",
    outline: "none", transition: "border .18s, box-shadow .18s", minHeight: "42px",
  },
  eye: {
    position: "absolute", right: "10px", top: "50%", transform: "translateY(-50%)",
    background: "none", border: "none", cursor: "pointer",
    color: "var(--text-muted)", fontSize: "16px", padding: "4px", lineHeight: 1,
    minWidth: "32px", minHeight: "32px", display: "flex", alignItems: "center", justifyContent: "center",
  },
  bars: { display: "flex", gap: "4px", marginTop: "6px" },
  bar:  { height: "4px", flex: 1, borderRadius: "2px", transition: "background .25s" },
  slabel: { fontSize: "11px", marginTop: "3px" },
  errMsg: { fontSize: "11px", color: "var(--error)", marginTop: "4px" },
};

export default function PasswordField({ id, label, value, onChange, error, showStrength = false }) {
  const [visible, setVisible] = useState(false);
  const [focused, setFocused] = useState(false);

  const strength = showStrength ? getPasswordStrength(value) : null;

  const inputStyle = {
    ...base.input,
    ...(error ? { border: "1px solid var(--error)" } : {}),
    ...(focused && !error ? { border: "1px solid var(--brand)", boxShadow: "0 0 0 2px rgba(40,116,240,.12)" } : {}),
  };

  return (
    <div style={base.field}>
      <label htmlFor={id} style={base.label}>{label}</label>
      <div style={base.wrap}>
        <input id={id} type={visible ? "text" : "password"} value={value}
          onChange={(e) => onChange(e.target.value)}
          onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
          style={inputStyle} autoComplete={showStrength ? "new-password" : "current-password"} />
        <button type="button" style={base.eye}
          onClick={() => setVisible((v) => !v)}
          aria-label={visible ? "Hide password" : "Show password"} tabIndex={-1}>
          {visible ? "🙈" : "👁"}
        </button>
      </div>
      {showStrength && value && (
        <>
          <div style={base.bars}>
            {[1, 2, 3, 4].map((seg) => (
              <div key={seg} style={{ ...base.bar, background: seg <= strength.score ? strength.color : "#e0e0e0" }} />
            ))}
          </div>
          <div style={{ ...base.slabel, color: strength.color || "var(--text-muted)" }}>
            {strength.label ? `${strength.label} password` : "Password strength"}
          </div>
        </>
      )}
      {error && <p style={base.errMsg}>{error}</p>}
    </div>
  );
}
